import { randomId, safeJsonParse } from './utils.js'

const KEYS = {
	theme: 'paperplane_theme',
	currentLocation: 'paperplane_current_location',
	myPlaneIds: 'paperplane_my_plane_ids',
	fueledPlaneIds: 'paperplane_fueled_plane_ids',
	recalledPlaneIds: 'paperplane_recalled_plane_ids',
	locationCache: 'paperplane_location_cache',
	profileName: 'paperplane_profile_name',
	profileAvatar: 'paperplane_profile_avatar',
	profileGender: 'paperplane_profile_gender',
	profileBio: 'paperplane_profile_bio',
	authUsers: 'paperplane_auth_users',
	authSession: 'paperplane_auth_session',
	voterKey: 'paperplane_voter_key',
	throwDraft: 'paperplane_throw_draft',
}

export function getTheme() {
	return uni.getStorageSync(KEYS.theme) || 'light'
}

export function setTheme(theme) {
	uni.setStorageSync(KEYS.theme, theme)
}

export function getCurrentLocation() {
	return uni.getStorageSync(KEYS.currentLocation) || ''
}

export function setCurrentLocation(name) {
	uni.setStorageSync(KEYS.currentLocation, name || '')
}

export function getMyPlaneIds() {
	return safeJsonParse(uni.getStorageSync(KEYS.myPlaneIds), [])
}

export function saveMyPlaneId(id) {
	const current = getMyPlaneIds().filter(item => item !== id)
	current.unshift(id)
	uni.setStorageSync(KEYS.myPlaneIds, JSON.stringify(current.slice(0, 100)))
}

export function removeMyPlaneId(id) {
	const current = getMyPlaneIds().filter(item => item !== id)
	uni.setStorageSync(KEYS.myPlaneIds, JSON.stringify(current))
}

export function getRecalledPlaneIds() {
	return safeJsonParse(uni.getStorageSync(KEYS.recalledPlaneIds), [])
}

export function saveRecalledPlaneId(id) {
	const current = getRecalledPlaneIds().filter(item => item !== id)
	current.unshift(id)
	uni.setStorageSync(KEYS.recalledPlaneIds, JSON.stringify(current.slice(0, 100)))
}

export function removeRecalledPlaneId(id) {
	const current = getRecalledPlaneIds().filter(item => item !== id)
	uni.setStorageSync(KEYS.recalledPlaneIds, JSON.stringify(current))
}

export function getFueledPlaneIds() {
	return safeJsonParse(uni.getStorageSync(KEYS.fueledPlaneIds), [])
}

export function saveFueledPlaneId(id) {
	const current = getFueledPlaneIds().filter(item => item !== id)
	current.unshift(id)
	uni.setStorageSync(KEYS.fueledPlaneIds, JSON.stringify(current.slice(0, 100)))
}

export function removeFueledPlaneId(id) {
	const current = getFueledPlaneIds().filter(item => item !== id)
	uni.setStorageSync(KEYS.fueledPlaneIds, JSON.stringify(current))
}

export function getLocationCache() {
	return safeJsonParse(uni.getStorageSync(KEYS.locationCache), [])
}

export function setLocationCache(locations) {
	uni.setStorageSync(KEYS.locationCache, JSON.stringify(locations || []))
}

export function getProfileName() {
	return uni.getStorageSync(KEYS.profileName) || '纸飞机同学'
}

export function setProfileName(name) {
	uni.setStorageSync(KEYS.profileName, (name || '').trim())
}

export function getProfileAvatar() {
	return uni.getStorageSync(KEYS.profileAvatar) || ''
}

export function setProfileAvatar(avatar) {
	uni.setStorageSync(KEYS.profileAvatar, avatar || '')
}

export function getProfileGender() {
	return uni.getStorageSync(KEYS.profileGender) || 'secret'
}

export function setProfileGender(gender) {
	uni.setStorageSync(KEYS.profileGender, gender || 'secret')
}

export function getProfileBio() {
	return uni.getStorageSync(KEYS.profileBio) || '把想说的话折进纸飞机里。'
}

export function setProfileBio(bio) {
	uni.setStorageSync(KEYS.profileBio, (bio || '').trim())
}

export function getAuthUsers() {
	return safeJsonParse(uni.getStorageSync(KEYS.authUsers), [])
}

export function saveAuthUsers(users) {
	uni.setStorageSync(KEYS.authUsers, JSON.stringify(users || []))
}

export function getAuthSession() {
	const session = safeJsonParse(uni.getStorageSync(KEYS.authSession), null)
	if (!session || typeof session !== 'object') return null
	if (!session.accessToken && !session.refreshToken) return null
	return session
}

export function setAuthSession(session) {
	if (!session) {
		clearAuthSession()
		return
	}
	uni.setStorageSync(KEYS.authSession, JSON.stringify(session))
}

export function clearAuthSession() {
	uni.removeStorageSync(KEYS.authSession)
}

export function getAccessToken() {
	return getAuthSession()?.accessToken || ''
}

export function getRefreshToken() {
	return getAuthSession()?.refreshToken || ''
}

export function setAuthSessionUser(user) {
	const session = getAuthSession()
	if (!session) return
	setAuthSession({
		...session,
		user: user || null,
	})
}

export function getVoterKey() {
	let value = uni.getStorageSync(KEYS.voterKey)
	if (!value) {
		value = randomId('voter')
		uni.setStorageSync(KEYS.voterKey, value)
	}
	return value
}

export function getThrowDraft() {
	return safeJsonParse(uni.getStorageSync(KEYS.throwDraft), null)
}

export function setThrowDraft(draft) {
	uni.setStorageSync(KEYS.throwDraft, JSON.stringify(draft || null))
}

export function clearThrowDraft() {
	uni.removeStorageSync(KEYS.throwDraft)
}
